<template>
  <v-container fluid>
    <v-row class="d-flex justify-center mb-9">
      <v-col cols="12" lg="12" xl="12">
        <v-card class="mx-auto main-card" elevation="4">
          <!-- Header -->
          <div class="card-header pa-5">
            <div class="d-flex align-center justify-center">
              <Icon icon="mdi:barcode" color="white" width="36" class="me-3" />
              <h2 class="text-white">طباعة باركود المنتجات</h2>
            </div>
            <p class="text-center mt-2" style="color: rgba(255,255,255,0.75); font-size: 14px;">
              إنشاء وطباعة ملصقات الباركود
            </p>
          </div>

          <v-card-text class="pa-6">
            <v-row>
              <!-- Form Section -->
              <v-col cols="12" md="5">
                <div class="form-section">
                  <h3 class="section-title mb-5">
                    <Icon icon="solar:settings-bold" width="24" class="me-2" style="vertical-align: middle;" />
                    إعدادات الباركود
                  </h3>

                  <!-- Barcode Number -->
                  <v-text-field
                    v-model="barcodeNumber"
                    label="رقم الباركود"
                    placeholder="أدخل رقم الباركود"
                    variant="outlined"
                    color="#624fc6"
                    type="number"
                    class="custom-input mb-1"
                    rounded
                    clearable
                    prepend-inner-icon="mdi-barcode-scan"
                    @input="onBarcodeInput"
                    :error-messages="barcodeError"
                    :messages="barcodeSuccess"
                    :loading="checkingBarcode"
                  >
                    <template v-slot:append-inner>
                      <v-tooltip location="bottom">
                        <template v-slot:activator="{ props }">
                          <v-btn
                            v-bind="props"
                            icon
                            size="small"
                            variant="tonal"
                            color="#624fc6"
                            @click="autoGenerateBarcode"
                            :loading="generatingBarcode"
                          >
                            <Icon icon="mdi:auto-fix" width="20" />
                          </v-btn>
                        </template>
                        <span>توليد رقم تلقائي</span>
                      </v-tooltip>
                    </template>
                  </v-text-field>

                  <!-- Show Price Toggle -->
                  <v-switch
                    v-model="showPrice"
                    label="إظهار السعر"
                    color="#624fc6"
                    class="mt-4"
                    hide-details
                    inset
                  />

                  <!-- Price Field -->
                  <v-text-field
                    v-if="showPrice"
                    v-model="price"
                    label="السعر"
                    placeholder="أدخل سعر المنتج"
                    variant="outlined"
                    color="#624fc6"
                    class="custom-input mt-4"
                    rounded
                    clearable
                    type="number"
                    min="0"
                    step="0.001"
                    prepend-inner-icon="mdi-cash"
                    hide-details
                  />


                  <!-- Label Dimensions -->
                  <h4 class="mt-5 mb-2" style="color: #1f2544;">
                    <Icon icon="solar:ruler-bold" width="20" class="me-1" style="vertical-align: middle;" />
                    أبعاد الملصق (مم)
                  </h4>
                  <v-row dense>
                    <v-col cols="6">
                      <v-text-field
                        v-model.number="labelWidth"
                        label="العرض (مم)"
                        variant="outlined"
                        color="#624fc6"
                        class="custom-input"
                        rounded
                        type="number"
                        min="10"
                        max="200"
                        prepend-inner-icon="mdi-arrow-left-right"
                        hide-details
                      />
                    </v-col>
                    <v-col cols="6">
                      <v-text-field
                        v-model.number="labelHeight"
                        label="الطول (مم)"
                        variant="outlined"
                        color="#624fc6"
                        class="custom-input"
                        rounded
                        type="number"
                        min="10"
                        max="200"
                        prepend-inner-icon="mdi-arrow-up-down"
                        hide-details
                      />
                    </v-col>
                  </v-row>

                  <!-- Action Buttons -->
                  <div class="d-flex flex-column gap mt-6">
                    <v-btn
                      @click="generateBarcode"
                      color="#624fc6"
                      size="large"
                      rounded="lg"
                      block
                      :disabled="!barcodeNumber"
                      class="action-btn"
                      elevation="2"
                    >
                      <Icon icon="solar:refresh-bold" width="22" class="me-2" />
                      توليد الباركود
                    </v-btn>

                    <v-btn
                      @click="printLabels"
                      color="#1f2544"
                      size="large"
                      rounded="lg"
                      block
                      :disabled="!barcodeGenerated"
                      class="action-btn mt-3"
                      elevation="2"
                    >
                      <Icon icon="solar:printer-bold" width="22" class="me-2" />
                      طباعة
                    </v-btn>
                  </div>
                </div>
              </v-col>

              <!-- Preview Section -->
              <v-col cols="12" md="7">
                <div class="preview-section">
                  <h3 class="section-title mb-5">
                    <Icon icon="solar:eye-bold" width="24" class="me-2" style="vertical-align: middle;" />
                    معاينة الملصق
                  </h3>

                  <!-- Empty State -->
                  <div v-if="!barcodeGenerated" class="empty-preview d-flex flex-column align-center justify-center">
                    <Icon icon="solar:barcode-line-duotone" width="80" color="#c5b8f0" />
                    <p class="mt-n16" style="color: #999; font-size: 18px;">
                      أدخل رقم الباركود ثم اضغط "توليد الباركود"
                    </p>
                  </div>

                  <!-- Label Preview -->
                  <div v-else class="preview-wrapper">
                    <div class="preview-scroll">
                      <div
                        v-for="n in quantity"
                        :key="n"
                        class="label-container"
                        :style="{ width: labelWidthPx + 'px', height: labelHeightPx + 'px' }"
                      >
                        <div class="label-content">
                          <svg :ref="el => { if (el) barcodeRefs[n - 1] = el }" class="barcode-svg"></svg>
                          <div v-if="showPrice && price" class="label-price">
                            {{ formatPrice(price) }}
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </v-col>
            </v-row>
          </v-card-text>
        </v-card>
      </v-col>
    </v-row>
  </v-container>
</template>

<script setup>
import { ref, computed, nextTick, watch, onMounted, getCurrentInstance } from "vue";
import JsBarcode from "jsbarcode";
import { server } from "@/config";

const { proxy } = getCurrentInstance();
const $http = proxy.$http;

const LABEL_W_KEY = "barcode-label-width";
const LABEL_H_KEY = "barcode-label-height";

const barcodeNumber = ref("");
const price = ref("");
const showPrice = ref(false);
const quantity = ref(1);
const labelWidth = ref(30);  // mm
const labelHeight = ref(40); // mm
const barcodeGenerated = ref(false);
const barcodeRefs = ref([]);

// Barcode validation state
const barcodeError = ref("");
const barcodeSuccess = ref("");
const checkingBarcode = ref(false);
const generatingBarcode = ref(false);
let checkTimeout = null;

// 1mm ≈ 3.7795px at 96 dpi
const MM_TO_PX = 3.7795;
const labelWidthPx = computed(() => Math.round(labelWidth.value * MM_TO_PX));
const labelHeightPx = computed(() => Math.round(labelHeight.value * MM_TO_PX));

// Load saved dimensions from localStorage
onMounted(() => {
  const savedW = localStorage.getItem(LABEL_W_KEY);
  const savedH = localStorage.getItem(LABEL_H_KEY);
  if (savedW) labelWidth.value = Number(savedW);
  if (savedH) labelHeight.value = Number(savedH);
});

// Persist dimensions to localStorage
watch(labelWidth, (v) => localStorage.setItem(LABEL_W_KEY, v));
watch(labelHeight, (v) => localStorage.setItem(LABEL_H_KEY, v));

function formatPrice(val) {
  const num = parseFloat(val);
  if (isNaN(num)) return "";
  return num.toLocaleString("en-US", {
    minimumFractionDigits: 0,
    maximumFractionDigits: 3,
  });
}

// Check if barcode already exists in backend
async function checkBarcodeExists(barcode) {
  if (!barcode) {
    barcodeError.value = "";
    barcodeSuccess.value = "";
    return;
  }
  checkingBarcode.value = true;
  barcodeError.value = "";
  barcodeSuccess.value = "";
  try {
    const res = await $http.get(`${server}/api/check_barcode`, { params: { barcode } });
    if (res.data.result?.exists) {
      barcodeError.value = "هذا الباركود مستخدم مسبقاً";
      barcodeSuccess.value = "";
    } else {
      barcodeError.value = "";
      barcodeSuccess.value = "الباركود متاح ✓";
    }
  } catch {
    // Silently ignore network errors during check
    barcodeError.value = "";
    barcodeSuccess.value = "";
  } finally {
    checkingBarcode.value = false;
  }
}

// Debounced handler for barcode input
function onBarcodeInput() {
  generateBarcode();
  clearTimeout(checkTimeout);
  checkTimeout = setTimeout(() => {
    checkBarcodeExists(barcodeNumber.value);
  }, 500);
}

// Auto-generate a unique 13-digit barcode
async function autoGenerateBarcode() {
  generatingBarcode.value = true;
  let attempts = 0;
  const maxAttempts = 10;

  while (attempts < maxAttempts) {
    // Generate a random 13-digit number
    const code = Array.from({ length: 13 }, () => Math.floor(Math.random() * 10)).join("");
    try {
      const res = await $http.get(`${server}/api/check_barcode`, { params: { barcode: code } });
      if (!res.data.data?.exists) {
        barcodeNumber.value = code;
        barcodeError.value = "";
        barcodeSuccess.value = "الباركود متاح ✓";
        generateBarcode();
        break;
      }
    } catch {
      // On error, just use the generated code
      barcodeNumber.value = code;
      generateBarcode();
      break;
    }
    attempts++;
  }
  generatingBarcode.value = false;
}

async function generateBarcode() {
  if (!barcodeNumber.value) {
    barcodeGenerated.value = false;
    return;
  }
  barcodeGenerated.value = true;

  await nextTick();
  renderBarcodes();
}

function renderBarcodes() {
  // Render preview barcodes
  for (let i = 0; i < quantity.value; i++) {
    const svgEl = barcodeRefs.value[i];
    if (svgEl) {
      JsBarcode(svgEl, barcodeNumber.value, {
        format: "CODE128",
        width: 1.5, // Make bars slightly thinner
        height: 55, // Significantly reduce height of bars
        displayValue: true,
        fontSize: 18, // Reduce font size
        font: "Cairo",
        textAlign: "center",
        textMargin: 2,
        margin: 0,
        background: "#ffffff",
        lineColor: "#000000",
      });
    }
  }
}

// Re-render when quantity, price, or dimensions change and barcode is active
watch([quantity, showPrice, price, labelWidth, labelHeight], async () => {
  if (barcodeGenerated.value && barcodeNumber.value) {
    await nextTick();
    renderBarcodes();
  }
});

function printLabels() {
  // Build the SVG HTML from the preview barcodes
  const labelsHtml = barcodeRefs.value
    .filter((el) => el)
    .map((svgEl) => {
      const svgMarkup = svgEl.outerHTML;
    const priceHtml =
      showPrice.value && price.value
        ? `<div class="print-price">${formatPrice(price.value)}</div>`
        : "";
      return `<div class="print-label">${svgMarkup}${priceHtml}</div>`;
    })
    .join("");

  const w = labelWidth.value;
  const h = labelHeight.value;

  const html = `<!DOCTYPE html>
<html dir="ltr">
<head>
<meta charset="utf-8">
<title>طباعة باركود</title>
<style>
  @page {
    size: ${w}mm ${h}mm;
    margin: 0;
  }
  * { 
    margin: 0; 
    padding: 0; 
    box-sizing: border-box; 
  }
  body, html {
    width: ${w}mm;
    height: ${h}mm;
    background: #fff;
    overflow: hidden;
  }
  .print-labels {
    width: 100%;
    height: 100%;
  }
  .print-label {
    width: ${w}mm;
    height: ${h}mm;
    page-break-after: always;
    page-break-inside: avoid;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    background: #fff;
    overflow: hidden;
    padding: 2mm 2mm 2mm 8mm;
  }
  .print-label:last-child {
    page-break-after: auto;
  }
  .print-label svg {
    display: block;
    max-width: 100% !important;
    max-height: ${showPrice.value ? '65%' : '85%'} !important;
    width: auto !important;
    height: auto !important;
    object-fit: contain;
  }
  .print-price {
    font-family: "Cairo", Arial, sans-serif;
    font-size: 11pt;
    font-weight: bold;
    color: #000;
    text-align: center;
    line-height: 1;
    margin-top: 1mm;
  }
</style>
</head>
<body>
  <div class="print-labels">${labelsHtml}</div>
</body>
</html>`;

  // Remove existing print iframe if any
  let oldFrame = document.getElementById("print-iframe");
  if (oldFrame) oldFrame.remove();

  // Create a hidden iframe
  const iframe = document.createElement("iframe");
  iframe.id = "print-iframe";
  iframe.style.position = "absolute";
  iframe.style.width = "0";
  iframe.style.height = "0";
  iframe.style.border = "none";
  document.body.appendChild(iframe);

  const doc = iframe.contentWindow.document;
  doc.open();
  doc.write(html);
  doc.close();

  // Print after images/scripts are loaded
  iframe.onload = () => {
    iframe.contentWindow.focus();
    iframe.contentWindow.print();
  };
}
</script>

<style scoped>


.main-card {
  overflow: hidden;
  box-shadow: 0px 0px 0px 0px !important;
  border-radius: 25px !important;
}

.card-header {
  background: linear-gradient(135deg, #624fc6 0%, #090040 100%);
  border-radius: 0 0 24px 24px;
}

.section-title {
  color: #1f2544;
  font-size: 18px;
  font-weight: 700;
  display: flex;
  align-items: center;
}

.form-section {
  background: #f9f8fe;
  border-radius: 16px;
  padding: 24px;
  height: 100%;
}

.preview-section {
  background: #f9f8fe;
  border-radius: 16px;
  padding: 24px;
  min-height: 550px;
}

.empty-preview {
  min-height: 450px;
  border: 2px dashed #e0d9f5;
  border-radius: 12px;
  background: #fdfcff;
}

.preview-wrapper {
  max-height: 500px;
  overflow-y: auto;
}

.preview-scroll {
  display: flex;
  flex-wrap: wrap;
  gap: 16px;
  justify-content: center;
}

.label-container {
  /* width & height are set via inline :style binding */
  border: 1px solid #ddd;
  border-radius: 6px;
  background: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.07);
  overflow: hidden;
}

.label-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  width: 100%;
  padding: 4px 2px;
}

.barcode-svg {
  width: 100%;
  height: auto;
  max-height: 90px;
}

.label-price {
  font-family: "Cairo", sans-serif;
  font-size: 18px;
  font-weight: 900;
  color: #000;
  text-align: center;
  line-height: 1.1;
  margin-top: 2px;
}

.action-btn {
  font-family: "Cairo", sans-serif;
  font-weight: 700;
  font-size: 16px;
  letter-spacing: 0;
}
</style>
