<template>
  <v-container>
    <v-row class="d-flex justify-center mb-9">
      <v-col cols="12" sm="12" md="12" lg="12">
        <v-card class="mx-auto card-table" width="100%">
          <v-data-table-server
            :headers="headers"
            :items="sales"
            v-model:options="pagination"
            v-model:page="pagination.page"
            :items-per-page="pagination.itemsPerPage"
            :items-length="pagination.itemsPerPage"
            :loading="loading"
            hide-default-footer
            fixed-header
            height="720"
            loading-text="جاري التحميل يرجى الأنتظار"
            :mobile-breakpoint="0"
          >
            <template v-slot:top>
              <v-toolbar flat color="#ffffff" class="mt-2">
                <h3 class="mx-2">جدول المبيعات</h3>
                <v-divider class="mx-2" inset vertical></v-divider>
                <v-tooltip location="bottom" interactive>
                  <template v-slot:activator="{ props }">
                    <v-btn @click="reset_table" fab icon x-small v-bind="props">
                      <Icon
                        icon="solar:smartphone-update-bold"
                        color="#624fc6"
                        width="30"
                      />
                    </v-btn>
                  </template>
                  <span>تحديث معلومات الجدول</span>
                </v-tooltip>

                <v-spacer></v-spacer>
                <v-text-field
                  v-model="barcode_query"
                  @input="query_change"
                  append-inner-icon="mdi-magnify"
                  label="بحث"
                  :class="display.smOnly ? 'mb-2' : ''"
                  class="font-weight-black mx-2"
                  color="#624fc6"
                  variant="outlined"
                  rounded
                  clearable
                  hide-details
                />
              </v-toolbar>
            </template>
            <template v-slot:item="{ item }">
              <tr>
                <td class="text-center font-weight-black">
                  {{ item.invoice_number }}
                </td>
                <td class="text-center font-weight-black">
                  <h4>{{ $filters.formatNumber(item.total) }} د.ع</h4>
                </td>
                <td class="text-center font-weight-black">
                  <h4 dir="ltr">
                    {{
                      $moment(item.created_at)
                        .tz("Asia/Baghdad")
                        .format("YYYY-MM-DD hh:mm A")
                    }}
                  </h4>
                </td>
                <td class="text-center font-weight-black">
                  <h4 v-if="item.retrieve == 1" style="color: red">
                    راجعة كليًا
                  </h4>
                  <h4 v-else-if="item.partial_return" style="color: orange">
                    راجعة جزئيًا
                  </h4>
                  <h4 v-else style="color: green">مكتملة</h4>
                </td>
                <!-- <td class="text-center font-weight-black">
                  <h4 v-if="item.sale_type == 0" style="color: green">نقد</h4>
                  <h4 v-else-if="item.sale_type == 1" style="color: orange">
                    آجل
                  </h4>
                </td> -->

                <td class="text-center font-weight-black">
                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        x-small
                        v-bind="props"
                        variant="text"
                        base-color="#624fc6"
                        @click="showItems(item.sale_items)"
                      >
                        <Icon
                          icon="solar:clipboard-list-bold-duotone"
                          color="#624fc6"
                          width="32"
                        />
                      </v-btn>
                    </template>
                    <span>عرض عناصر الفاتورة</span>
                  </v-tooltip>
                </td>
                <td class="text-center font-weight-black">
                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        x-small
                        v-bind="props"
                        variant="text"
                        base-color="#D32F2F"
                        :disabled="item.retrieve == 1"
                        @click="popRetrieveAllItems(item.id)"
                        :loading="retrieve_loading && item.id === sale_id"
                      >
                        <Icon
                          icon="solar:clipboard-remove-bold-duotone"
                          color="#D32F2F"
                          width="32"
                        />
                        <template v-slot:loader>
                          <span class="custom-loader">
                            <v-icon color="#D32F2F">mdi-cached</v-icon>
                          </span>
                        </template>
                      </v-btn>
                    </template>
                    <span>استرجاع كامل</span>
                  </v-tooltip>
                </td>
                <td class="text-center font-weight-black">
                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        x-small
                        v-bind="props"
                        variant="text"
                        base-color="#37474F"
                        @click="printInvoice(item)"
                      >
                        <Icon
                          icon="solar:printer-bold-duotone"
                          color="#37474F"
                          width="32"
                        />
                      </v-btn>
                    </template>
                    <span>طباعة الفاتورة</span>
                  </v-tooltip>
                </td>
                <td class="text-center font-weight-black">
                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        x-small
                        v-bind="props"
                        variant="text"
                        base-color="#37474F"
                        :disabled="item.name == null && item.city == null"
                        @click="showInfoUser(item)"
                      >
                        <Icon
                          icon="solar:display-bold-duotone"
                          color="#4A148C"
                          width="32"
                        />
                      </v-btn>
                    </template>
                    <span>معلومات الزبون</span>
                  </v-tooltip>

                  <v-tooltip location="bottom" interactive>
                    <template v-slot:activator="{ props }">
                      <v-btn
                        icon
                        x-small
                        v-bind="props"
                        variant="text"
                        base-color="#37474F"
                        :disabled="isExpired(item)"
                        @click="changeSaleType(item)"
                        :loading="loading_change && item.id === sale_id"
                      >
                        <Icon
                          icon="material-symbols:change-circle-rounded"
                          color="#37474F"
                          width="32"
                        />
                      </v-btn>
                    </template>
                    <span>تغير حالة البيع</span>
                  </v-tooltip>
                </td>
              </tr>
            </template>
          </v-data-table-server>
          <div class="text-center py-5">
            <v-row>
              <v-col cols="12" sm="6" md="6" lg="6">
                <v-pagination
                  v-model="pagination.page"
                  :length="pageCount"
                  rounded="circle"
                  variant="elevated"
                  color="#ffffff"
                  active-color="#624fc6"
                ></v-pagination>
              </v-col>
              <v-col cols="12" sm="6" md="6" lg="6">
                <v-select
                  v-model="pagination.itemsPerPage"
                  :items="items"
                  class="font-weight-black px-2"
                  label="عدد العناصر"
                  color="#624fc6"
                  variant="outlined"
                  rounded
                  persistent-hint
                  hide-details="auto"
                ></v-select>
              </v-col>
              <v-col cols="12" sm="6" md="3" lg="3">
                <Selects
                  v-on:update-value="status = $event"
                  v-model="status"
                  label="حالات البيع"
                  itemValue="value"
                  itemText="type"
                  :items="statuses"
                  class="px-2"
                />
              </v-col>
              <!-- <v-col cols="12" sm="6" md="3" lg="3">
                <Selects
                  v-on:update-value="sale_type = $event"
                  v-model="sale_type"
                  label="نوع الشراء"
                  itemValue="value"
                  itemText="type"
                  :items="sale_types"
                  class=""
                />
              </v-col> -->
              <v-col cols="12" sm="6" md="3" lg="3" class="pr-4">
                <InputDate
                  v-model="date_from"
                  @clearInput="date_from = null"
                  label="من تاريخ"
                  class="pl-2"
                />
              </v-col>
              <v-col cols="12" sm="6" md="3" lg="3" class="pl-5">
                <InputDate
                  v-model="date_to"
                  @clearInput="date_to = null"
                  label="الى"
                />
              </v-col>
            </v-row>
          </div>
        </v-card>
      </v-col>
      <ShowItems
        :dialog="dialog"
        @popClose="dialog = false"
        :items="product_items"
        @itemUpdated="updateProductItems"
      />
      <PopRetrieveAllItems
        :dialog="dialog_retrieve_all_items"
        @popClose="dialog_retrieve_all_items = false"
        @retrieveAllItems="retrieveAllItems"
      />
      <PopSalesDebit
        :dialog="dialog_change_sale"
        :totalPrice="item_sale?.total"
        @popClose="dialog_change_sale = false"
        @addSales="ChangeSaleType"
      />
      <PopShowInfoUser
        :dialog="dialog_info_user"
        :info_user="info_user"
        @popClose="dialog_info_user = false"
      />
      <CheckPassword :dialog="dialog2" @CheckPassword="dialog2 = false" />
    </v-row>
  </v-container>
</template>
<script setup>
import { ref, computed, watch } from "vue";
import { useSalesStore } from "@/stores/sales";
import InvoiceReceipt from "@/components/layout/invoice.vue";
import Selects from "@/components/layout/Selects.vue";
import InputDate from "@/components/layout/InputDate.vue";
import ShowItems from "@/components/sales/ShowItems.vue";
import PopRetrieveAllItems from "@/components/sales/PopRetrieveAllItems.vue";
import PopSalesDebit from "@/components/sales/PopSalesDebit.vue";
import PopShowInfoUser from "@/components/sales/PopShowInfoUser.vue";
import CheckPassword from "@/components/layout/CheckPassword.vue";

import moment from "moment-timezone";
import { h, render } from "vue";
import { nextTick } from "vue";
// import { server } from "@/config";
import { useDisplay } from "vuetify";

const display = useDisplay();

const salesStore = useSalesStore();

const items = [5, 10, 15, 20, 25,50,100,200];
const pagination = ref({ page: 1, itemsPerPage: 10, sortBy: [], sortDesc: [] });
const dialog = ref(false);
const dialog_retrieve_all_items = ref(false);
const product_items = ref([]);
const sale_id = ref(null);
const dialog_change_sale = ref(false);

const dialog2 = ref(true);

const dialog_info_user = ref(false);
const info_user = ref(null);

const item_sale = ref(null);

const statuses = [
  { type: "مكتملة", value: "completed" },
  { type: "راجعة كليًا", value: "full_return" },
  { type: "راجعة جزئيًا", value: "partial_return" },
];

// const sale_types = [
//   { type: "نقد", value: "cash" },
//   { type: "آجل", value: "debt" },
// ];

const headers = [
  {
    title: "باركود",
    value: "barcode",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },

  {
    title: "المجموع الكلي ",
    value: "purchase_price",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "التاريخ",
    value: "created_at",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "حالة البيع",
    value: "color",
    align: "center",
    width: "150px",
    headerProps: { class: "white--text text-body-1" },
  },
  // {
  //   title: "نوع الشراء",
  //   value: "sale_type",
  //   align: "center",
  //   width: "150px",
  //   headerProps: { class: "white--text text-body-1" },
  // },
  {
    title: "عرض العناصر",
    value: "color",
    align: "center",
    width: "130px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "استرجاع",
    value: "color",
    align: "center",
    width: "130px",
    headerProps: { class: "white--text text-body-1" },
  },

  {
    title: "الفاتورة",
    value: "name",
    align: "center",
    width: "190px",
    headerProps: { class: "white--text text-body-1" },
  },
  {
    title: "العمليات",
    value: "name",
    align: "center",
    width: "160px",
    headerProps: { class: "white--text text-body-1" },
  },
];

// ✅ Computed properties using Pinia state
const pageCount = computed(() => salesStore.pageCount);

const barcode_query = computed({
  get: () => salesStore.barcode_query,
  set: (val) => (salesStore.barcode_query = val),
});
const params = computed({
  get: () => salesStore.params,
  set: (val) => (salesStore.params = val),
});
const status = computed({
  get: () => salesStore.status,
  set: (val) => (salesStore.status = val),
});
const sale_type = computed({
  get: () => salesStore.sale_type,
  set: (val) => (salesStore.sale_type = val),
});
const date_from = computed({
  get: () => salesStore.date_from,
  set: (val) => (salesStore.date_from = val),
});

const date_to = computed({
  get: () => salesStore.date_to,
  set: (val) => (salesStore.date_to = val),
});

const sales = computed(() => salesStore.sales);
const loading = computed(() => salesStore.table_loading);
const retrieve_loading = computed(() => salesStore.retrieve_loading);
const loading_change = computed(() => salesStore.loading_change);

const isExpired = (item) => {
  // استثناء الطلبات الآجلة
  if (item.sale_type === 1) return false;

  const now = moment().tz("Asia/Baghdad");
  const createdAt = moment(item.created_at).tz("Asia/Baghdad");

  // تحقق من أن تاريخ الطلب هو اليوم فقط
  const isSameDay = now.isSame(createdAt, "day");

  // إذا ليس نفس اليوم، نعتبره منتهي مباشرة
  if (!isSameDay) return true;

  // تحقق من فرق الوقت (بالساعات)
  return now.diff(createdAt, "hours", true) >= 1;
};

// ✅ Methods
function get_sales() {
  const par = { ...pagination.value };
  params.value = par;
  salesStore.get_sales();
}

let timerId = null;

function query_change() {
  clearTimeout(timerId);
  timerId = setTimeout(() => {
    get_sales();
  }, 200);
}

function reset_table() {
  salesStore.reset_table();
  salesStore.get_sales();
}

function showItems(items) {
  product_items.value = items;
  dialog.value = true;
}
function changeSaleType(item) {
  item_sale.value = item;
  dialog_change_sale.value = true;
}

function updateProductItems(updatedSale) {
  product_items.value = updatedSale.sale_items;
}

function popRetrieveAllItems(id) {
  sale_id.value = id;
  dialog_retrieve_all_items.value = true;
}

function showInfoUser(item) {
  info_user.value = item;
  dialog_info_user.value = true;
}

const retrieveAllItems = async () => {
  dialog_retrieve_all_items.value = false;
  let data = {
    sale_id: sale_id.value,
  };
  try {
    await salesStore.retrieve_all_items(data);
    sale_id.value = null;
  } catch (e) {
    // error already handled in store
  }
};

async function ChangeSaleType(userDebtor) {
  let data = {};
  dialog_change_sale.value = false;

  data["debtor_id"] = userDebtor["debtor_id"];
  data["payment_amount"] = userDebtor["payment_amount"];
  data["sale_type"] = 1;
  data["sale_id"] = item_sale.value.id;
  sale_id.value = item_sale.value.id;

  try {
    await salesStore.change_sale_type(data);
    item_sale.value = null;
  } catch (e) {
    // error already handled in store
  }
}

// طباعة فاتورة
const paperSize = ref("size-80");
const nameStore = ref("علاء حداد فرع الديوانية");

let isPrinting = false;

function printInvoice(items) {
  if (isPrinting) return;
  isPrinting = true;

  // حاوية الطباعة المباشرة تحت body
  const container = document.createElement("div");
  container.id = "print-root"; // مهم جداً للـ CSS أدناه
  container.style.position = "fixed";
  container.style.left = "0";
  container.style.top = "0";
  container.style.zIndex = "2147483647";
  document.body.appendChild(container);

  const cleanup = () => {
    render(null, container);
    container.remove();
    window.removeEventListener("afterprint", cleanup);
    isPrinting = false;
  };

  const vnode = h(InvoiceReceipt, {
    purchasedItems: items.sale_items,
    nameStore: nameStore.value,
    paperSize: paperSize.value,
    saleType: items.sale_type,
    invoiceId: items.invoice_number,
    date: items.created_at,
    onReady: async () => {
      await nextTick();
      requestAnimationFrame(() => {
        window.addEventListener("afterprint", cleanup, { once: true });
        window.print(); // نسخة واحدة فقط
      });
    },
  });

  render(vnode, container);
}

// ✅ Watch pagination to refetch data
watch(
  pagination,
  () => {
    get_sales();
  },
  { deep: true }
);

watch(barcode_query, (newVal) => {
  if (newVal === null || newVal === "") {
    pagination.value.page = 1;
    get_sales();
  }
});

watch(status, (newVal) => {
  if (newVal && typeof newVal === "object" && newVal.value) {
    get_sales();
  }
});
watch(sale_type, (newVal) => {
  if (newVal && typeof newVal === "object" && newVal.value) {
    get_sales();
  }
});
watch(date_from, (newVal) => {
  if (newVal != null && newVal != "") {
    get_sales();
  }
});
watch(date_to, (newVal) => {
  if (newVal != null && newVal != "") {
    get_sales();
  }
});
</script>
<style scoped>
.card-table {
  box-shadow: 0px 0px 0px 0px !important;
  border-radius: 25px !important;
}
</style>
